INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "ヤマト", 0.0, 100, "2024/10/31 12:00:00", 3001100, 130011, 3001, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", "2030/01/01 14:59:59", 2.1, 2);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 4, "ヤマト", 0.0, 101, "2024/10/31 12:00:00", 3001101, 130011, 3001, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", "2030/01/01 14:59:59", 5.68, 2);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "ヤマト", 0.0, 102, "2024/10/31 12:00:00", 3001102, 130011, 3001, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", "2030/01/01 14:59:59", 0.0, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "フブキ", 0.0, 100, "2024/10/31 12:00:00", 3002100, 130211, 3002, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", "2030/01/01 14:59:59", 0.0, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "フブキ", 0.0, 101, "2024/10/31 12:00:00", 3002101, 130211, 3002, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", "2030/01/01 14:59:59", 0.0, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 5, "フブキ", 0.0, 102, "2024/10/31 12:00:00", 3002102, 130211, 3002, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", "2030/01/01 14:59:59", 8.53, 2);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 7, "フブキ", 0.0, 103, "2024/10/31 12:00:00", 3002103, 130211, 3002, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", "2030/01/01 14:59:59", 5.67, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "フブキ", 0.0, 104, "2024/10/31 12:00:00", 3002104, 130211, 3002, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", "2030/01/01 14:59:59", 0.0, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 3, "フブキ", 0.0, 300, "2024/10/31 12:00:00", 3002300, 130211, 3004, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", "2030/01/01 14:59:59", 0.0, 3);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 7, "フブキ", 0.0, 301, "2024/10/31 12:00:00", 3002400, 130211, 3005, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", "2030/01/01 14:59:59", 0.0, 7);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 2, "フブキ", 0.0, 200, "2024/10/31 12:00:00", 3003200, 130211, 3003, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", "2030/01/01 14:59:59", 4.4, 1);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 7, "フブキ", 0.0, 201, "2024/10/31 12:00:00", 3003201, 130211, 3003, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", "2030/01/01 14:59:59", 0.0, 7);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (-416.5, 1, "フブキ", 0.0, 202, "2024/10/31 12:00:00", 3003202, 130211, 3003, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", "2030/01/01 14:59:59", 5.6, 2);
